$pgv_lang["alphabet_upper"]				= "Alfabet de majÃšscules";
$pgv_lang["alphabet_upper_help"]			= "~#pgv_lang[alphabet_upper]#~<br /><br />Alfabet de lletres majÃšscules en aquest idioma. S'utilitza per ordenar les llistes de noms.";
